// Pass the transaction exactly as Relay provides it — including maxFeePerGas and
// maxPriorityFeePerGas. These are set by Relay to ensure the tx is valid at execution
// time. Stripping them causes wallets to re-simulate with different gas prices,
// which produces "likely to fail" warnings when the simulation uses wrong state.
const txParams = {
  to: txData.to as `0x${string}`,
  data: txData.data as `0x${string}`,
  value: safeValue(txData.value),
  ...(txData.maxFeePerGas && { maxFeePerGas: safeValue(txData.maxFeePerGas) }),
  ...(txData.maxPriorityFeePerGas && { maxPriorityFeePerGas: safeValue(txData.maxPriorityFeePerGas) }),
}

console.log('Sending transaction:', { to: txParams.to, value: txParams.value.toString() })

input.newString:
// Send only to/data/value — never forward Relay's maxFeePerGas/maxPriorityFeePerGas.
// Those values are set at quote time and become stale within seconds. If the current
// base fee exceeds the quoted maxFeePerGas, MetaMask simulates the tx as failing and
// shows "This transaction is likely to fail". Letting the wallet pick current gas
// prices avoids this entirely — the calldata validity is independent of gas price.
const txParams = {
  to: txData.to as `0x${string}`,
  data: txData.data as `0x${string}`,
  value: safeValue(txData.value),
}

console.log('Sending transaction:', { to: txParams.to, value: txParams.value.toString() })
